    .map(entry => {
      if (typeof entry === 'string') return normalizeUrl(entry);
      if (entry && typeof entry === 'object') return normalizeUrl(entry.url || entry.href);
      return '';
    })
    .filter(Boolean);
}

function deriveSiteUrlFromRss(raw) {
  const rssUrl = normalizeUrl(raw);
  if (!rssUrl) return '';

  try {
    const parsed = new URL(rssUrl);
    const strippedPath = parsed.pathname
      .replace(/\/(?:feed|rss|atom)(?:\.xml)?\/?$/i, '/')
      .replace(/\/(?:index\.)?(?:rss|atom)\.xml\/?$/i, '/')
      .replace(/\/feed\/?$/i, '/');
