  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

function clean(s) {
  return String(s || '')
    .replace(/\r/g, '')
    .replace(/[\t ]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function splitParagraphs(text) {
  return clean(text)
    .split(/\n\n+/)
    .map(p => clean(p))
    .filter(Boolean);
}

function splitLongParagraph(paragraph, maxChars) {
  const text = clean(paragraph);
  if (!text) return [];
  if (text.length <= maxChars) return [text];

  const sentences = text.split(/(?<=[.!?])\s+/).map(clean).filter(Boolean);
  if (sentences.length <= 1) {
    const hardChunks = [];
    for (let i = 0; i < text.length; i += maxChars) {
      const chunk = clean(text.slice(i, i + maxChars));
      if (chunk) hardChunks.push(chunk);
    }
    return hardChunks;
  }

  const out = [];
  let buf = '';
  for (const sentence of sentences) {
    if (sentence.length > maxChars) {
      if (buf) {
        out.push(buf);
        buf = '';
      }
      for (let i = 0; i < sentence.length; i += maxChars) {
        const hardChunk = clean(sentence.slice(i, i + maxChars));
        if (hardChunk) out.push(hardChunk);
      }
      continue;
    }

    const candidate = buf ? `${buf} ${sentence}` : sentence;
    if (candidate.length > maxChars && buf) {
      out.push(buf);
      buf = sentence;
    } else {
      buf = candidate;
    }
  }

  if (buf) out.push(buf);
  return out;
}

// Simple signal scoring: prioritizes paragraphs likely to produce Velvet Paradox concepts.
const SIGNAL = [
  'pressure','fracture','collapse','repair','restraint','rupture','erosion','threshold','damage','bruise','stain',
  'residue','seep','crack','buckle','warp','misalign','aftermath','tension','constraint','weight','drift','fragile',
  'ritual','memory','identity','veil','shadow','fog','silence','ruin','relic','static','paradox'
];

function scorePara(p) {
  const t = p.toLowerCase();
  let score = 0;
  for (const w of SIGNAL) if (t.includes(w)) score += 1;
  if (/(stone|plaster|velvet|metal|dust|smoke|haze|wet|rust|cloth|feather|fur|wax|candle)/i.test(p)) score += 2;
  return score;
}

const j = $json;
const ctx = j.ctx;
const source = j.source;
const crawlProfile = (j.crawl_profile && typeof j.crawl_profile === 'object') ? j.crawl_profile : {};
const extract = (crawlProfile.extract && typeof crawlProfile.extract === 'object') ? crawlProfile.extract : {};
const pages = Array.isArray(j.pages) ? j.pages : [];

const maxFragChars = Math.max(400, Math.min(Number(extract.max_fragment_chars || ctx.max_fragment_chars || 2200), 8000));
const maxFragsPerPage = Math.max(1, Math.min(Number(extract.max_fragments_per_page || ctx.max_fragments_per_page || 8), 24));

const out = [];

for (const page of pages) {
  const paras = splitParagraphs(page.text);
  const ranked = paras
    .map((p, idx) => ({ p, idx, s: scorePara(p) }))
    .sort((a, b) => (b.s - a.s) || (a.idx - b.idx));

  const chosen = ranked
    .slice(0, Math.min(ranked.length, maxFragsPerPage * 3))
    .sort((a, b) => a.idx - b.idx)
    .flatMap(({ p }) => splitLongParagraph(p, maxFragChars));

  let buf = '';
  let chunkIndex = 0;

  for (const p of chosen) {
    const add = buf ? (buf + '\n\n' + p) : p;
    if (add.length > maxFragChars && buf) {
      const cleaned = clean(buf);
      const hash = fnv1a(`${ctx.trace_id}::${ctx.crawl_run_id}::${page.url}::${chunkIndex}::${cleaned}`);
      out.push({
        ctx,
        source,
        fragment: {
          fragment_id: `tvpx_fg_${hash}`,
          crawl_run_id: ctx.crawl_run_id,
          source_id: ctx.source_id,
          page_url: page.url,
          page_title: page.title || '',
          chunk_index: chunkIndex,
          fragment_hash: hash,
          raw_text: buf,
          cleaned_text: cleaned,
          token_estimate: Math.ceil(cleaned.length / 4),
          qa_status: 'clean'
        }
      });
      buf = p;
      chunkIndex += 1;
      if (chunkIndex >= maxFragsPerPage) break;
    } else {
      buf = add;
    }
  }

  if (buf && chunkIndex < maxFragsPerPage) {
    const cleaned = clean(buf);
    const hash = fnv1a(`${ctx.trace_id}::${ctx.crawl_run_id}::${page.url}::${chunkIndex}::${cleaned}`);
    out.push({
      ctx,
      source,
      fragment: {
        fragment_id: `tvpx_fg_${hash}`,
        crawl_run_id: ctx.crawl_run_id,
        source_id: ctx.source_id,
        page_url: page.url,
        page_title: page.title || '',
        chunk_index: chunkIndex,
        fragment_hash: hash,
        raw_text: buf,
        cleaned_text: cleaned,
        token_estimate: Math.ceil(cleaned.length / 4),
        qa_status: 'clean'
      }
    });
  }
}

if (!out.length) {
  return [{ json: { ctx, source, crawl_profile: crawlProfile, fragments: [], empty: true } }];
}

return out.map(o => ({ json: { ...o, crawl_profile: crawlProfile } }));

/**
 * Update Crawl Ledger Final
 * - Marks run completed, writes counts
 * - Ensures ctx preserved after fragment upserts
 */

const base = $items('Normalize Apify Run Output')[0].json;
const ctx = base.ctx;
const source = base.source;
const fragmentRows = $items('Chunk And Clean Text').filter(item => item.json?.fragment?.fragment_id);
const rawDatasetRows = $items('Get dataset items').flatMap(item => {
  const row = item.json || {};
  if (Array.isArray(row.items)) return row.items;
  if (Array.isArray(row.data)) return row.data;
  return [row];
}).filter(row => row && Object.keys(row).length);

return [{
  json: {
    ctx,
    source,
    crawl_run_final: {
      crawl_run_id: ctx.crawl_run_id,
      status: 'completed',
      completed_at: new Date().toISOString(),
      raw_item_count: Number(rawDatasetRows.length || 0),
      page_count: Number(($items('Normalize Crawl Items')[0]?.json?.pages || []).length),
      fragment_count: fragmentRows.length
    }
  }
}];
